1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies (underpopulation) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die (underpopulation, 1 neighbor each) — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("live cell with 4 neighbors dies (overpopulation) — center of full 3x3 block dies", () => {
15	    const fullBlock: [number, number][] = [
16	      [0, 0], [1, 0], [2, 0],
17	      [0, 1], [1, 1], [2, 1],
18	      [0, 2], [1, 2], [2, 2],
19	    ];
20	    const result = nextGeneration(fullBlock);
21	    expect(result).not.toContainEqual([1, 1]);
22	  });
23	  it("dead cell with exactly 3 live neighbors becomes alive (reproduction) — [(0,0),(1,0),(0,1)] produces (1,1)", () => {
24	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
25	    expect(result).toContainEqual([1, 1]);
26	  });
27	  it("live cell with 2 or 3 neighbors survives — center cell of T-shape with 3 neighbors survives", () => {
28	    const tShape: [number, number][] = [[0, 0], [1, 0], [2, 0], [1, 1]];
29	    const result = nextGeneration(tShape);
30	    expect(result).toContainEqual([1, 0]);
31	  });
32	  it.todo("block still-life is unchanged — [(0,0),(1,0),(0,1),(1,1)] → same");
33	  it.todo("blinker oscillates: vertical to horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]");
34	  it.todo("handles negative coordinates — block at negative offsets remains stable");
35	});
